"use client";

import { motion, AnimatePresence, type Variants } from "framer-motion";
import { useEffect, useState } from "react";
import type { Slide as SlideType, Theme } from "@/types";

interface SlideProps {
  slide: SlideType;
  theme: Theme;
  direction?: number;
}

const containerVariants: Variants = {
  enter: (direction: number) => ({
    x: direction > 0 ? 80 : -80,
    opacity: 0,
  }),
  center: {
    x: 0,
    opacity: 1,
    transition: {
      duration: 0.4,
      ease: "easeOut",
      staggerChildren: 0.1,
      delayChildren: 0.1,
    },
  },
  exit: (direction: number) => ({
    x: direction < 0 ? 80 : -80,
    opacity: 0,
    transition: { duration: 0.3 },
  }),
};

export default function Slide({ slide, theme, direction = 1 }: SlideProps) {
  const [elements, setElements] = useState<string[]>([]);

  useEffect(() => {
    const div = document.createElement("div");
    div.innerHTML = slide.html;
    const children = Array.from(div.children).map((el) => el.outerHTML);
    setElements(children);
  }, [slide.html]);

  return (
    <motion.div
      key={slide.id}
      custom={direction}
      variants={containerVariants}
      initial="enter"
      animate="center"
      exit="exit"
      className="absolute inset-0 flex flex-col justify-center px-12 py-10 overflow-hidden"
      style={{
        backgroundColor: theme.bg,
        color: theme.text,
      }}
    >
      {elements.map((html, i) => (
        <AnimatedElement
          key={i}
          html={html}
          theme={theme}
          index={i}
        />
      ))}
    </motion.div>
  );
}

interface AnimatedElementProps {
  html: string;
  theme: Theme;
  index: number;
}

function AnimatedElement({ html, theme, index }: AnimatedElementProps) {
  const tag = html.match(/^<(\w+)/)?.[1] ?? "";
  const delay = index * 0.1;

  const getInitial = () => {
    if (tag === "h1" || tag === "h2" || tag === "h3") {
      return { opacity: 0, scale: 0.95, y: -10 };
    }
    if (tag === "ul" || tag === "ol") {
      return { opacity: 0, x: -20 };
    }
    if (tag === "pre") {
      return { opacity: 0, y: 10 };
    }
    return { opacity: 0, y: 12 };
  };

  const getAnimate = () => {
    if (tag === "h1" || tag === "h2" || tag === "h3") {
      return { opacity: 1, scale: 1, y: 0, x: 0 };
    }
    if (tag === "ul" || tag === "ol") {
      return { opacity: 1, x: 0, y: 0, scale: 1 };
    }
    if (tag === "pre") {
      return { opacity: 1, y: 0, x: 0, scale: 1 };
    }
    return { opacity: 1, y: 0, x: 0, scale: 1 };
  };

  return (
    <motion.div
      initial={getInitial()}
      animate={getAnimate()}
      transition={{ duration: 0.4, ease: "easeOut", delay }}
      className="slide-element"
      style={getElementStyle(tag, theme)}
      dangerouslySetInnerHTML={{ __html: html }}
    />
  );
}

function getElementStyle(tag: string, theme: Theme): React.CSSProperties {
  const base: React.CSSProperties = { marginBottom: "0.75rem" };

  if (tag === "h1") {
    return {
      ...base,
      color: theme.heading,
      fontSize: "2.5rem",
      fontWeight: 800,
      lineHeight: 1.2,
      marginBottom: "1rem",
    };
  }
  if (tag === "h2") {
    return {
      ...base,
      color: theme.heading,
      fontSize: "1.875rem",
      fontWeight: 700,
      lineHeight: 1.3,
    };
  }
  if (tag === "h3") {
    return {
      ...base,
      color: theme.accent,
      fontSize: "1.5rem",
      fontWeight: 600,
    };
  }
  if (tag === "pre") {
    return {
      ...base,
      backgroundColor: theme.codeBg,
      color: theme.codeText,
      padding: "1rem 1.25rem",
      borderRadius: "0.5rem",
      fontSize: "0.875rem",
      overflowX: "auto",
      border: `1px solid ${theme.border}`,
      fontFamily: "monospace",
    };
  }
  if (tag === "blockquote") {
    return {
      ...base,
      borderLeft: `4px solid ${theme.accent}`,
      paddingLeft: "1rem",
      color: theme.text,
      opacity: 0.85,
      fontStyle: "italic",
    };
  }
  return base;
}


--- components/SlidePreview.tsx ---
"use client";

import { AnimatePresence } from "framer-motion";
import { useRef, useState } from "react";
import Slide from "./Slide";
import { useSlides } from "@/hooks/useSlides";
import { getTheme } from "@/lib/themes";

export default function SlidePreview() {
  const { slides, currentIndex, theme, nextSlide, prevSlide } = useSlides();
  const [direction, setDirection] = useState(1);
  const currentTheme = getTheme(theme);

  const handleNext = () => {
    setDirection(1);
    nextSlide();
  };

  const handlePrev = () => {
    setDirection(-1);
    prevSlide();
  };

  const currentSlide = slides[currentIndex];

  return (
    <div
      className="flex flex-col h-full"
      style={{ backgroundColor: currentTheme.bg }}
    >
      {/* Slide area */}
      <div
        className="relative flex-1 overflow-hidden"
        style={{
          border: `1px solid ${currentTheme.border}`,
          borderRadius: "0.5rem",
          margin: "1rem",
        }}
      >
        {slides.length === 0 ? (
          <div
            className="absolute inset-0 flex items-center justify-center"
            style={{ color: currentTheme.text, opacity: 0.5 }}
          >
            <p>No slides yet. Start writing Markdown!</p>
          </div>
        ) : (
          <AnimatePresence custom={direction} mode="wait">
            {currentSlide && (
              <Slide
                key={currentSlide.id}
                slide={currentSlide}
                theme={currentTheme}
                direction={direction}
              />
            )}
          </AnimatePresence>
        )}
      </div>

      {/* Navigation */}
      <div
        className="flex items-center justify-between px-4 py-3"
        style={{ borderTop: `1px solid ${currentTheme.border}` }}
      >
        <button
          onClick={handlePrev}
          disabled={currentIndex === 0}
          className="px-4 py-2 rounded font-medium text-sm transition-opacity disabled:opacity-30 cursor-pointer disabled:cursor-not-allowed"
          style={{
            backgroundColor: currentTheme.accent,
            color: currentTheme.bg,
          }}
        >
          ← Prev
        </button>

        <div
          className="flex gap-1.5 items-center"
          style={{ color: currentTheme.text, opacity: 0.6, fontSize: "0.85rem" }}
        >
          {slides.map((_, i) => (
            <button
              key={i}
              onClick={() => {
                setDirection(i > currentIndex ? 1 : -1);
                useSlides.getState().setCurrentIndex(i);
              }}
              className="w-2 h-2 rounded-full transition-all cursor-pointer"
              style={{
                backgroundColor:
                  i === currentIndex ? currentTheme.accent : currentTheme.border,
                transform: i === currentIndex ? "scale(1.4)" : "scale(1)",
              }}
              aria-label={`Go to slide ${i + 1}`}
            />
          ))}
        </div>

        <button
          onClick={handleNext}
          disabled={currentIndex === slides.length - 1}
          className="px-4 py-2 rounded font-medium text-sm transition-opacity disabled:opacity-30 cursor-pointer disabled:cursor-not-allowed"
          style={{
            backgroundColor: currentTheme.accent,
            color: currentTheme.bg,
          }}
        >
          Next →
        </button>
      </div>
    </div>
  );
}


